t.script:
//
document.addEventListener('DOMContentLoaded', function() {
    // State
    let linesData = [];

    // DOM
    const planSelect = document.getElementById('plan_select');
    const loadBtn = document.getElementById('load_btn');
    const exportBtn = document.getElementById('export_btn');
    const loadingDiv = document.getElementById('loading');
    const resultsSection = document.getElementById('results_section');
    const selectedPanel = document.getElementById('selected_panel');
    const errorDiv = document.getElementById('error_message');
    const errorText = document.getElementById('error_text');
    const headerCheckbox = document.getElementById('header_checkbox');
    const selectAllBtn = document.getElementById('select_all_btn');
    const deselectAllBtn = document.getElementById('deselect_all_btn');
    const clearSelectionBtn = document.getElementById('clear_selection_btn');

    // Numeric field definitions
    const numericFields = [
        {key: 'pu_st_am', label: 'პირვანდელი ღირებულება'},
        {key: 'pu_ac_am', label: 'მიმდინარე ღირებულება'},
        {key: 'pu_diff', label: 'სხვაობა'},
        {key: 'pcon_am', label: 'ხელშეკრულების თანხა'},
        {key: 'pc_re_am', label: 'დარჩ. რეს. ხელშეკრ.'},
        {key: 'paim_am', label: 'გადახდილი თანხა'},
        {key: 'pa_re_am', label: 'დარჩენილი რესურსი'},
        {key: 'budget_lines_allocated', label: 'გამოყოფილი'},
        {key: 'remaining_to_allocate', label: 'დარჩენილი გასანაწილ.'}
    ];

    // Events
    planSelect.addEventListener('change', function() {
        loadBtn.disabled = !planSelect.value;
        hideResults();
        hideError();
    });

    loadBtn.addEventListener('click', loadLines);
    exportBtn.addEventListener('click', exportCSV);

    headerCheckbox.addEventListener('change', function() {
        toggleAll(headerCheckbox.checked);
    });
    selectAllBtn.addEventListener('click', function() {
        toggleAll(true);
        headerCheckbox.checked = true;
    });
    deselectAllBtn.addEventListener('click', function() {
        toggleAll(false);
        headerCheckbox.checked = false;
    });
    clearSelectionBtn.addEventListener('click', function() {
        toggleAll(false);
        headerCheckbox.checked = false;
    });

    function loadLines() {
        const planId = planSelect.value;
        if (!planId) return;

        loadingDiv.style.display = 'block';
        resultsSection.style.display = 'none';
        selectedPanel.style.display = 'none';
        hideError();

        fetch('/budget/get_plan_lines', {
            method: 'POST',
            headers: {'Content-Type': 'application/json'},
            body: JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: {purchase_plan_id: planId}
            })
        })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            loadingDiv.style.display = 'none';
            if (data.result && data.result.length > 0) {
                linesData = data.result;
                renderTable(linesData);
                renderTotalCards(linesData);
                resultsSection.style.display = 'block';
                exportBtn.disabled = false;
                headerCheckbox.checked = false;
                selectedPanel.style.display = 'none';
            } else if (data.result && data.result.length === 0) {
                showError('არჩეულ გეგმაში ხაზები არ მოიძებნა');
            } else {
                showError('შეცდომა მონაცემების ჩატვირთვისას');
            }
        })
        .catch(function(err) {
            loadingDiv.style.display = 'none';
            showError('შეცდომა: ' + err.message);
        });
    }

    function renderTable(lines) {
        var tbody = document.getElementById('lines_tbody');
        var tfoot = document.getElementById('lines_tfoot');
        tbody.innerHTML = '';
        tfoot.innerHTML = '';

        var badge = document.getElementById('lines_count_badge');
        badge.textContent = lines.length + ' ხაზი';

        // Compute totals
        var totals = {};
        numericFields.forEach(function(f) { totals[f.key] = 0; });

        lines.forEach(function(line, idx) {
            numericFields.forEach(function(f) {
                totals[f.key] += (line[f.key] || 0);
            });

            var tr = document.createElement('tr');
            tr.setAttribute('data-index', idx);

            var curr = line.currency_symbol || '';

            tr.innerHTML =
                '<td class="text-center"><input type="checkbox" class="row-checkbox" data-index="' + idx + '"/></td>' +
                '<td>' + (idx + 1) + '</td>' +
                '<td>' + escHtml(line.plan_name) + '</td>' +
                '<td>' + escHtml(line.cpv_code) + '</td>' +
                '<td>' + escHtml(line.cpv_name) + '</td>' +
                '<td>' + escHtml(line.funding_source) + '</td>' +
                '<td>' + escHtml(line.purchase_method) + '</td>' +
                '<td>' + escHtml(line.purchase_reason) + '</td>' +
                '<td>' + escHtml(line.vadebi) + '</td>' +
                '<td class="text-right">' + fmtNum(line.pu_st_am) + '</td>' +
                '<td class="text-right">' + fmtNum(line.pu_ac_am) + '</td>' +
                '<td class="text-right">' + fmtNum(line.pu_diff) + '</td>' +
                '<td class="text-right">' + fmtNum(line.pcon_am) + '</td>' +
                '<td class="text-right">' + fmtNum(line.pc_re_am) + '</td>' +
                '<td class="text-right">' + fmtNum(line.paim_am) + '</td>' +
                '<td class="text-right">' + fmtNum(line.pa_re_am) + '</td>' +
                '<td class="text-right">' + fmtNum(line.budget_lines_allocated) + '</td>' +
                '<td class="text-right">' + fmtNum(line.remaining_to_allocate) + '</td>';

            tbody.appendChild(tr);
        });

        // Footer totals row
        var tfootTr = document.createElement('tr');
        tfootTr.innerHTML =
            '<td colspan="9" class="text-right font-weight-bold" style="font-size: 0.9rem;">ჯამი:</td>' +
            '<td class="text-right">' + fmtNum(totals.pu_st_am) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.pu_ac_am) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.pu_diff) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.pcon_am) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.pc_re_am) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.paim_am) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.pa_re_am) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.budget_lines_allocated) + '</td>' +
            '<td class="text-right">' + fmtNum(totals.remaining_to_allocate) + '</td>';
        tfoot.appendChild(tfootTr);

        // Bind checkbox events
        var checkboxes = tbody.querySelectorAll('.row-checkbox');
        checkboxes.forEach(function(cb) {
            cb.addEventListener('change', onRowSelectionChange);
        });

        // Also allow clicking the row (not the checkbox cell) to toggle
        var rows = tbody.querySelectorAll('tr');
        rows.forEach(function(row) {
            row.addEventListener('click', function(e) {
                if (e.target.type === 'checkbox') return;
                var cb = row.querySelector('.row-checkbox');
                if (cb) {
                    cb.checked = !cb.checked;
                    onRowSelectionChange();
                }
            });
        });
    }

    function renderTotalCards(lines) {
        var container = document.getElementById('total_cards');
        var totals = {};
        numericFields.forEach(function(f) { totals[f.key] = 0; });
        lines.forEach(function(line) {
            numericFields.forEach(function(f) {
                totals[f.key] += (line[f.key] || 0);
            });
        });

        var colors = ['#667eea', '#764ba2', '#f093fb', '#4BC0C0', '#36A2EB', '#FF6384', '#56ab2f', '#FF9F40', '#9966FF'];
        var html = '';
        numericFields.forEach(function(f, i) {
            html += '<div class="col-lg-3 col-md-4 col-sm-6 mb-3">' +
                '<div class="total-card shadow-sm" style="background: ' + colors[i % colors.length] + ';">' +
                    '<div class="total-label">' + f.label + '</div>' +
                    '<div class="total-value">' + fmtNum(totals[f.key]) + '</div>' +
                '</div>' +
            '</div>';
        });
        container.innerHTML = html;
    }

    function onRowSelectionChange() {
        var checkboxes = document.querySelectorAll('#lines_tbody .row-checkbox');
        var selectedIndices = [];
        checkboxes.forEach(function(cb) {
            if (cb.checked) {
                selectedIndices.push(parseInt(cb.getAttribute('data-index')));
                cb.closest('tr').classList.add('row-selected');
            } else {
                cb.closest('tr').classList.remove('row-selected');
            }
        });

        if (selectedIndices.length > 0) {
            renderSelectedSums(selectedIndices);
            selectedPanel.style.display = 'block';
        } else {
            selectedPanel.style.display = 'none';
        }

        // Update header checkbox state
        headerCheckbox.checked = selectedIndices.length === linesData.length;
        headerCheckbox.indeterminate = selectedIndices.length > 0 && selectedIndices.length < linesData.length;
    }

    function renderSelectedSums(selectedIndices) {
        var sums = {};
        numericFields.forEach(function(f) { sums[f.key] = 0; });

        selectedIndices.forEach(function(idx) {
            var line = linesData[idx];
            if (line) {
                numericFields.forEach(function(f) {
                    sums[f.key] += (line[f.key] || 0);
                });
            }
        });

        document.getElementById('selected_count').textContent = selectedIndices.length;

        var container = document.getElementById('selected_sums_row');
        var html = '';
        numericFields.forEach(function(f) {
            html += '<div class="col-lg-3 col-md-4 col-sm-6">' +
                '<div class="sum-card">' +
                    '<div class="sum-label">' + f.label + '</div>' +
                    '<div class="sum-value">' + fmtNum(sums[f.key]) + '</div>' +
                '</div>' +
            '</div>';
        });
        container.innerHTML = html;
    }

    function toggleAll(checked) {
        var checkboxes = document.querySelectorAll('#lines_tbody .row-checkbox');
        checkboxes.forEach(function(cb) { cb.checked = checked; });
        onRowSelectionChange();
    }

    function exportCSV() {
        if (!linesData || linesData.length === 0) {
            showError('ექსპორტისთვის მონაცემები არ არის');
            return;
        }

        var headers = [
            '#', 'გეგმა', 'CPV კოდი', 'CPV დასახელება', 'დაფინანსების წყარო',
            'შესყიდვის საშუალება', 'შესყიდვის საფუძველი', 'ვადები',
            'პირვანდელი ღირებულება', 'მიმდინარე ღირებულება', 'სხვაობა',
            'ხელშეკრულების თანხა', 'დარჩ. რეს. ხელშეკრ.',
            'გადახდილი თანხა', 'დარჩენილი რესურსი',
            'გამოყოფილი', 'დარჩენილი გასანაწილ.'
        ];

        var csv = '\uFEFF' + headers.join(',') + '\n';

        linesData.forEach(function(line, idx) {
            csv += (idx + 1) + ',' +
                '"' + (line.plan_name || '') + '",' +
                '"' + (line.cpv_code || '') + '",' +
                '"' + (line.cpv_name || '') + '",' +
                '"' + (line.funding_source || '') + '",' +
                '"' + (line.purchase_method || '') + '",' +
                '"' + (line.purchase_reason || '') + '",' +
                '"' + (line.vadebi || '') + '",' +
                line.pu_st_am + ',' + line.pu_ac_am + ',' + line.pu_diff + ',' +
                line.pcon_am + ',' + line.pc_re_am + ',' +
                line.paim_am + ',' + line.pa_re_am + ',' +
                line.budget_lines_allocated + ',' + line.remaining_to_allocate + '\n';
        });

        var blob = new Blob([csv], {type: 'text/csv;charset=utf-8;'});
        var url = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = url;
        a.download = 'purchase_plan_lines_' + new Date().toISOString().split('T')[0] + '.csv';
        a.style.display = 'none';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    }

    function fmtNum(val) {
        if (val === 0) return '0.00';
        return parseFloat(val).toLocaleString('ka-GE', {minimumFractionDigits: 2, maximumFractionDigits: 2});
    }

    function escHtml(str) {
        if (!str) return '';
        var div = document.createElement('div');
        div.appendChild(document.createTextNode(str));
        return div.innerHTML;
    }

    function hideResults() {
        resultsSection.style.display = 'none';
        selectedPanel.style.display = 'none';
        exportBtn.disabled = true;
        linesData = [];
    }

    function showError(msg) {
        errorText.textContent = msg;
        errorDiv.style.display = 'block';
    }

    function hideError() {
        errorDiv.style.display = 'none';
    }
});
//
